(function () {
  function clear(ctx) {
    var canvas = ctx.canvas;
    ctx.clearRect(0, 0, canvas.width, canvas.height);
  }

  function fitCanvas(ctx) {
    var canvas = ctx.canvas;
    var rect = canvas.getBoundingClientRect();
    if (rect.width && rect.height) {
      canvas.width = Math.round(rect.width);
      canvas.height = Math.round(rect.height);
    }
  }

  function drawDoughnut(ctx, config) {
    var data = config.data.datasets[0].data || [];
    var colors = config.data.datasets[0].backgroundColor || [];
    var total = data.reduce(function (sum, value) { return sum + Number(value || 0); }, 0) || 1;
    var cx = ctx.canvas.width / 2;
    var cy = ctx.canvas.height / 2 - 10;
    var radius = Math.min(ctx.canvas.width, ctx.canvas.height) * 0.32;
    var start = -Math.PI / 2;
    data.forEach(function (value, index) {
      var angle = (Number(value || 0) / total) * Math.PI * 2;
      ctx.beginPath();
      ctx.moveTo(cx, cy);
      ctx.arc(cx, cy, radius, start, start + angle);
      ctx.closePath();
      ctx.fillStyle = colors[index] || '#7c6ff7';
      ctx.fill();
      start += angle;
    });
    ctx.globalCompositeOperation = 'destination-out';
    ctx.beginPath();
    ctx.arc(cx, cy, radius * 0.7, 0, Math.PI * 2);
    ctx.fill();
    ctx.globalCompositeOperation = 'source-over';
  }

  function drawBar(ctx, config) {
    var data = config.data.datasets[0].data || [];
    var colors = config.data.datasets[0].backgroundColor || [];
    var labels = config.data.labels || [];
    var max = Math.max.apply(null, data.concat([1]));
    var width = ctx.canvas.width;
    var height = ctx.canvas.height;
    var base = height - 34;
    var left = 28;
    var gap = 18;
    var barWidth = (width - left - gap * (data.length + 1)) / Math.max(data.length, 1);
    ctx.strokeStyle = 'rgba(139,146,165,.25)';
    ctx.beginPath();
    ctx.moveTo(left, 12);
    ctx.lineTo(left, base);
    ctx.lineTo(width - 8, base);
    ctx.stroke();
    data.forEach(function (value, index) {
      var h = ((Number(value || 0) / max) * (base - 22));
      var x = left + gap + index * (barWidth + gap);
      var y = base - h;
      ctx.fillStyle = colors[index] || '#7c6ff7';
      ctx.fillRect(x, y, Math.max(barWidth, 8), h);
      ctx.fillStyle = '#8b92a5';
      ctx.font = '11px sans-serif';
      ctx.textAlign = 'center';
      ctx.fillText(String(labels[index] || ''), x + barWidth / 2, height - 10);
    });
  }

  window.Chart = function Chart(ctx, config) {
    fitCanvas(ctx);
    clear(ctx);
    if (config.type === 'bar') drawBar(ctx, config);
    else drawDoughnut(ctx, config);
    this.destroy = function () { clear(ctx); };
    this.update = function () { clear(ctx); if (config.type === 'bar') drawBar(ctx, config); else drawDoughnut(ctx, config); };
  };
})();
